     1→#ifndef TOKEN_H
     2→#define TOKEN_H
     3→
     4→#include <string>
     5→#include <ostream>
     6→
     7→namespace zlang {
     8→
     9→/**
    10→ * TokenType: Z-Lang의 모든 토큰 타입
    11→ *
    12→ * 【 어휘 분석(Lexing)의 산물 】
    13→ * 소스 코드 → Lexer → Token 스트림 → Parser
    14→ */
    15→enum class TokenType {
    16→    // 특수 토큰
    17→    END_OF_FILE = 0,
    18→    NEWLINE,
    19→
    20→    // 리터럴
    21→    INTEGER,       // 123, 456
    22→    FLOAT,         // 3.14, 2.71
    23→    BOOL_TRUE,     // true
    24→    BOOL_FALSE,    // false
    25→    STRING,        // "hello"
    26→    IDENTIFIER,    // variable_name
    27→
    28→    // 키워드
    29→    KW_FN,         // fn
    30→    KW_LET,        // let
    31→    KW_RETURN,     // return
    32→    KW_IF,         // if
    33→    KW_ELSE,       // else
    34→    KW_WHILE,      // while
    35→    KW_TRUE,       // true (literal로도 사용)
    36→    KW_FALSE,      // false (literal로도 사용)
    37→
    38→    // 【 Step 3: Exception Handling Keywords 】
    39→    KW_TRY,        // try
    40→    KW_CATCH,      // catch
    41→    KW_FINALLY,    // finally
    42→    KW_THROW,      // throw
    43→
    44→    // 타입 키워드
    45→    KW_I32,        // i32
    46→    KW_I64,        // i64
    47→    KW_F32,        // f32
    48→    KW_F64,        // f64
    49→    KW_BOOL,       // bool
    50→    KW_VOID,       // void
    51→    KW_STRING,     // string
    52→
    53→    // 연산자
    54→    PLUS,          // +
    55→    MINUS,         // -
    56→    STAR,          // *
    57→    SLASH,         // /
    58→    PERCENT,       // %
    59→    CARET,         // ^
    60→
    61→    // 비교 연산자
    62→    EQ,            // ==
    63→    NE,            // !=
    64→    LT,            // <
    65→    GT,            // >
    66→    LE,            // <=
    67→    GE,            // >=
    68→
    69→    // 논리 연산자
    70→    AND,           // &&
    71→    OR,            // ||
    72→    NOT,           // !
    73→
    74→    // 할당 연산자
    75→    ASSIGN,        // =
    76→
    77→    // 구두점
    78→    LPAREN,        // (
    79→    RPAREN,        // )
    80→    LBRACE,        // {
    81→    RBRACE,        // }
    82→    LBRACKET,      // [
    83→    RBRACKET,      // ]
    84→    SEMICOLON,     // ;
    85→    COMMA,         // ,
    86→    COLON,         // :
    87→    DOT,           // .
    88→    ARROW,         // ->
    89→    AMPERSAND,     // & (참조)
    90→
    91→    // 속성 (Attribute)
    92→    HASH_BRACKET,  // #[ (속성 시작)
    93→
    94→    // 오류
    95→    UNKNOWN,
    96→    ERROR
    97→};
    98→
    99→/**
   100→ * Token: 단일 토큰을 표현
   101→ *
   102→ * 예:
   103→ *   source: "let x: i64 = 42;"
   104→ *   tokens:
   105→ *     Token(KW_LET, "let", line=1, col=1)
   106→ *     Token(IDENTIFIER, "x", line=1, col=5)
   107→ *     Token(COLON, ":", line=1, col=6)
   108→ *     Token(KW_I64, "i64", line=1, col=8)
   109→ *     Token(ASSIGN, "=", line=1, col=12)
   110→ *     Token(INTEGER, "42", line=1, col=14)
   111→ *     Token(SEMICOLON, ";", line=1, col=16)
   112→ */
   113→struct Token {
   114→    TokenType type;
   115→    std::string lexeme;    // 원본 텍스트 (예: "123", "variable_name")
   116→    std::string literal;   // 파싱된 값 (예: integer 123, float 3.14)
   117→    int line;
   118→    int column;
   119→
   120→    Token()
   121→        : type(TokenType::END_OF_FILE), lexeme(""), literal(""),
   122→          line(0), column(0) {}
   123→
   124→    Token(TokenType t, const std::string& lex, const std::string& lit = "",
   125→          int l = 0, int c = 0)
   126→        : type(t), lexeme(lex), literal(lit), line(l), column(c) {}
   127→
   128→    // 디버깅용 출력
   129→    std::string toString() const {
   130→        return std::string(
   131→            "[" + std::to_string(line) + ":" + std::to_string(column) +
   132→            "] " + lexeme + " (" + std::to_string(static_cast<int>(type)) + ")"
   133→        );
   134→    }
   135→};
   136→
   137→/**
   138→ * TokenType → 문자열 변환 (디버깅용)
   139→ */
   140→inline std::string tokenTypeToString(TokenType type) {
   141→    switch (type) {
   142→        case TokenType::END_OF_FILE:    return "EOF";
   143→        case TokenType::NEWLINE:        return "NEWLINE";
   144→        case TokenType::INTEGER:        return "INTEGER";
   145→        case TokenType::FLOAT:          return "FLOAT";
   146→        case TokenType::BOOL_TRUE:      return "TRUE";
   147→        case TokenType::BOOL_FALSE:     return "FALSE";
   148→        case TokenType::STRING:         return "STRING";
   149→        case TokenType::IDENTIFIER:     return "IDENTIFIER";
   150→        case TokenType::KW_FN:          return "fn";
   151→        case TokenType::KW_LET:         return "let";
   152→        case TokenType::KW_RETURN:      return "return";
   153→        case TokenType::KW_IF:          return "if";
   154→        case TokenType::KW_ELSE:        return "else";
   155→        case TokenType::KW_WHILE:       return "while";
   156→        case TokenType::KW_I32:         return "i32";
   157→        case TokenType::KW_I64:         return "i64";
   158→        case TokenType::KW_F32:         return "f32";
   159→        case TokenType::KW_F64:         return "f64";
   160→        case TokenType::KW_BOOL:        return "bool";
   161→        case TokenType::KW_VOID:        return "void";
   162→        case TokenType::KW_STRING:      return "string";
   163→        case TokenType::PLUS:           return "+";
   164→        case TokenType::MINUS:          return "-";
   165→        case TokenType::STAR:           return "*";
   166→        case TokenType::SLASH:          return "/";
   167→        case TokenType::PERCENT:        return "%";
   168→        case TokenType::CARET:          return "^";
   169→        case TokenType::EQ:             return "==";
   170→        case TokenType::NE:             return "!=";
   171→        case TokenType::LT:             return "<";
   172→        case TokenType::GT:             return ">";
   173→        case TokenType::LE:             return "<=";
   174→        case TokenType::GE:             return ">=";
   175→        case TokenType::AND:            return "&&";
   176→        case TokenType::OR:             return "||";
   177→        case TokenType::NOT:            return "!";
   178→        case TokenType::ASSIGN:         return "=";
   179→        case TokenType::LPAREN:         return "(";
   180→        case TokenType::RPAREN:         return ")";
   181→        case TokenType::LBRACE:         return "{";
   182→        case TokenType::RBRACE:         return "}";
   183→        case TokenType::LBRACKET:       return "[";
   184→        case TokenType::RBRACKET:       return "]";
   185→        case TokenType::SEMICOLON:      return ";";
   186→        case TokenType::COMMA:          return ",";
   187→        case TokenType::COLON:          return ":";
   188→        case TokenType::DOT:            return ".";
   189→        case TokenType::ARROW:          return "->";
   190→        case TokenType::AMPERSAND:      return "&";
   191→        case TokenType::HASH_BRACKET:   return "#[";
   192→        default:                        return "UNKNOWN";
   193→    }
   194→}
   195→
   196→} // namespace zlang
   197→
   198→#endif // TOKEN_H
   199→

