     1→#include "Parser.h"
     2→#include <iostream>
     3→#include <cassert>
     4→
     5→namespace zlang {
     6→
     7→// ============================================================================
     8→// 생성자
     9→// ============================================================================
    10→
    11→Parser::Parser(const std::vector<Token>& tok)
    12→    : tokens(tok), current(0) {
    13→}
    14→
    15→// ============================================================================
    16→// 【 진입점: parse() 】
    17→// ============================================================================
    18→
    19→std::shared_ptr<ProgramNode> Parser::parse() {
    20→    return parseProgram();
    21→}
    22→
    23→// ============================================================================
    24→// 【 Program & Function 파싱 】
    25→// ============================================================================
    26→
    27→std::shared_ptr<ProgramNode> Parser::parseProgram() {
    28→    auto program = std::make_shared<ProgramNode>();
    29→
    30→    while (!isAtEnd()) {
    31→        if (check(TokenType::KW_FN)) {
    32→            auto func = parseFunction();
    33→            if (func) {
    34→                program->functions.push_back(func);
    35→            }
    36→        } else {
    37→            reportError("Expected 'fn' at top level");
    38→            synchronize();
    39→            advance();
    40→        }
    41→    }
    42→
    43→    return program;
    44→}
    45→
    46→std::shared_ptr<FunctionNode> Parser::parseFunction() {
    47→    if (!match(TokenType::KW_FN)) {
    48→        reportError("Expected 'fn'");
    49→        return nullptr;
    50→    }
    51→
    52→    Token name_token = consume(TokenType::IDENTIFIER, "Expected function name");
    53→    std::string func_name = name_token.lexeme;
    54→
    55→    consume(TokenType::LPAREN, "Expected '(' after function name");
    56→    auto params = parseParameters();
    57→    consume(TokenType::RPAREN, "Expected ')' after parameters");
    58→
    59→    consume(TokenType::ARROW, "Expected '->' before return type");
    60→    Type return_type = parseType();
    61→
    62→    auto block = parseBlock();
    63→    if (!block) {
    64→        return nullptr;
    65→    }
    66→
    67→    return std::make_shared<FunctionNode>(func_name, params, return_type, block);
    68→}
    69→
    70→std::vector<Parameter> Parser::parseParameters() {
    71→    std::vector<Parameter> params;
    72→
    73→    if (check(TokenType::RPAREN)) {
    74→        return params;  // 파라미터 없음
    75→    }
    76→
    77→    do {
    78→        Token param_name = consume(TokenType::IDENTIFIER, "Expected parameter name");
    79→        consume(TokenType::COLON, "Expected ':' after parameter name");
    80→        Type param_type = parseType();
    81→
    82→        params.push_back({param_name.lexeme, param_type});
    83→
    84→        if (!match(TokenType::COMMA)) {
    85→            break;
    86→        }
    87→    } while (!check(TokenType::RPAREN));
    88→
    89→    return params;
    90→}
    91→
    92→Type Parser::parseType() {
    93→    Type type;
    94→
    95→    // 포인터 타입: &T
    96→    if (match(TokenType::AMPERSAND)) {
    97→        type.is_pointer = true;
    98→        auto pointee = std::make_unique<Type>(parseType());
    99→        type.pointee_type = pointee.release();
   100→        return type;
   101→    }
   102→
   103→    // 배열 타입: [T; N]
   104→    if (match(TokenType::LBRACKET)) {
   105→        type.is_array = true;
   106→        auto elem_type = std::make_unique<Type>(parseType());
   107→        type.element_type = elem_type.release();
   108→
   109→        consume(TokenType::SEMICOLON, "Expected ';' in array type");
   110→
   111→        Token size_token = consume(TokenType::INTEGER, "Expected array size");
   112→        type.array_size = std::stoi(size_token.lexeme);
   113→
   114→        consume(TokenType::RBRACKET, "Expected ']' after array type");
   115→        return type;
   116→    }
   117→
   118→    // 기본 타입
   119→    type.base = tokenTypeToBuiltinType(peek().type);
   120→
   121→    if (type.base == BuiltinType::Unknown) {
   122→        // 커스텀 타입일 수 있음 (현재는 지원하지 않음)
   123→        reportError("Unknown type: " + peek().lexeme);
   124→    }
   125→
   126→    advance();
   127→    return type;
   128→}
   129→
   130→// ============================================================================
   131→// 【 Statement 파싱 】
   132→// ============================================================================
   133→
   134→std::shared_ptr<ASTNode> Parser::parseStatement() {
   135→    if (check(TokenType::KW_LET)) {
   136→        return parseVarDecl();
   137→    }
   138→    if (check(TokenType::KW_IF)) {
   139→        return parseIfStatement();
   140→    }
   141→    if (check(TokenType::KW_WHILE)) {
   142→        return parseWhileStatement();
   143→    }
   144→    if (check(TokenType::KW_RETURN)) {
   145→        return parseReturnStatement();
   146→    }
   147→    // 【 Step 3: try-catch-finally 파싱 】
   148→    if (check(TokenType::KW_TRY)) {
   149→        return parseTryCatch();
   150→    }
   151→    if (check(TokenType::LBRACE)) {
   152→        return parseBlock();
   153→    }
   154→
   155→    // Expression statement
   156→    auto expr = parseExpression();
   157→    match(TokenType::SEMICOLON);
   158→    return expr;
   159→}
   160→
   161→std::shared_ptr<VarDeclNode> Parser::parseVarDecl() {
   162→    if (!match(TokenType::KW_LET)) {
   163→        reportError("Expected 'let'");
   164→        return nullptr;
   165→    }
   166→
   167→    Token var_name = consume(TokenType::IDENTIFIER, "Expected variable name");
   168→    consume(TokenType::COLON, "Expected ':' after variable name");
   169→
   170→    Type var_type = parseType();
   171→
   172→    consume(TokenType::ASSIGN, "Expected '=' after type");
   173→    auto init_expr = parseExpression();
   174→
   175→    consume(TokenType::SEMICOLON, "Expected ';' after variable declaration");
   176→
   177→    auto var_decl = std::make_shared<VarDeclNode>(var_name.lexeme, var_type, init_expr);
   178→
   179→    return var_decl;
   180→}
   181→
   182→std::shared_ptr<BlockNode> Parser::parseBlock() {
   183→    if (!match(TokenType::LBRACE)) {
   184→        reportError("Expected '{'");
   185→        return nullptr;
   186→    }
   187→
   188→    auto block = std::make_shared<BlockNode>();
   189→
   190→    while (!check(TokenType::RBRACE) && !isAtEnd()) {
   191→        auto stmt = parseStatement();
   192→        if (stmt) {
   193→            block->statements.push_back(stmt);
   194→        }
   195→    }
   196→
   197→    consume(TokenType::RBRACE, "Expected '}'");
   198→    return block;
   199→}
   200→
   201→std::shared_ptr<IfNode> Parser::parseIfStatement() {
   202→    if (!match(TokenType::KW_IF)) {
   203→        reportError("Expected 'if'");
   204→        return nullptr;
   205→    }
   206→
   207→    auto cond = parseExpression();
   208→    auto then_block = parseBlock();
   209→
   210→    if (!then_block) {
   211→        return nullptr;
   212→    }
   213→
   214→    std::shared_ptr<BlockNode> else_block = nullptr;
   215→    if (match(TokenType::KW_ELSE)) {
   216→        else_block = parseBlock();
   217→    }
   218→
   219→    return std::make_shared<IfNode>(cond, then_block, else_block);
   220→}
   221→
   222→std::shared_ptr<WhileNode> Parser::parseWhileStatement() {
   223→    if (!match(TokenType::KW_WHILE)) {
   224→        reportError("Expected 'while'");
   225→        return nullptr;
   226→    }
   227→
   228→    auto cond = parseExpression();
   229→    auto body = parseBlock();
   230→
   231→    if (!body) {
   232→        return nullptr;
   233→    }
   234→
   235→    return std::make_shared<WhileNode>(cond, body);
   236→}
   237→
   238→std::shared_ptr<ReturnNode> Parser::parseReturnStatement() {
   239→    if (!match(TokenType::KW_RETURN)) {
   240→        reportError("Expected 'return'");
   241→        return nullptr;
   242→    }
   243→
   244→    std::shared_ptr<ASTNode> return_expr = nullptr;
   245→
   246→    // return 뒤에 식이 없을 수도 있음
   247→    if (!check(TokenType::SEMICOLON)) {
   248→        return_expr = parseExpression();
   249→    }
   250→
   251→    consume(TokenType::SEMICOLON, "Expected ';' after return statement");
   252→
   253→    auto ret = std::make_shared<ReturnNode>();
   254→    ret->value = return_expr;
   255→
   256→    return ret;
   257→}
   258→
   259→// ============================================================================
   260→// 【 Expression 파싱 (우선순위 처리) 】
   261→// ============================================================================
   262→
   263→std::shared_ptr<ASTNode> Parser::parseExpression() {
   264→    return parseAssignment();
   265→}
   266→
   267→std::shared_ptr<ASTNode> Parser::parseAssignment() {
   268→    auto expr = parseLogicalOr();
   269→
   270→    if (match(TokenType::ASSIGN)) {
   271→        auto right = parseAssignment();
   272→
   273→        // ✅ FIX: AssignmentNode를 올바르게 생성
   274→        // expr이 Identifier여야만 assignment의 대상이 될 수 있음
   275→        if (auto identifier = std::dynamic_pointer_cast<IdentifierNode>(expr)) {
   276→            return std::make_shared<AssignmentNode>(identifier->name, right);
   277→        } else {
   278→            error("Assignment target must be a variable");
   279→            return expr;
   280→        }
   281→    }
   282→
   283→    return expr;
   284→}
   285→
   286→std::shared_ptr<ASTNode> Parser::parseLogicalOr() {
   287→    auto left = parseLogicalAnd();
   288→
   289→    while (match(TokenType::OR)) {
   290→        auto right = parseLogicalAnd();
   291→        left = std::make_shared<BinaryOpNode>(BinaryOp::Or, left, right);
   292→    }
   293→
   294→    return left;
   295→}
   296→
   297→std::shared_ptr<ASTNode> Parser::parseLogicalAnd() {
   298→    auto left = parseEquality();
   299→
   300→    while (match(TokenType::AND)) {
   301→        auto right = parseEquality();
   302→        left = std::make_shared<BinaryOpNode>(BinaryOp::And, left, right);
   303→    }
   304→
   305→    return left;
   306→}
   307→
   308→std::shared_ptr<ASTNode> Parser::parseEquality() {
   309→    auto left = parseRelational();
   310→
   311→    while (check(TokenType::EQ) || check(TokenType::NE)) {
   312→        TokenType op_type = advance().type;
   313→        auto right = parseRelational();
   314→        left = std::make_shared<BinaryOpNode>(tokenTypeToBinaryOp(op_type), left, right);
   315→    }
   316→
   317→    return left;
   318→}
   319→
   320→std::shared_ptr<ASTNode> Parser::parseRelational() {
   321→    auto left = parseAdditive();
   322→
   323→    while (check(TokenType::LT) || check(TokenType::GT) ||
   324→           check(TokenType::LE) || check(TokenType::GE)) {
   325→        TokenType op_type = advance().type;
   326→        auto right = parseAdditive();
   327→        left = std::make_shared<BinaryOpNode>(tokenTypeToBinaryOp(op_type), left, right);
   328→    }
   329→
   330→    return left;
   331→}
   332→
   333→std::shared_ptr<ASTNode> Parser::parseAdditive() {
   334→    auto left = parseMultiplicative();
   335→
   336→    while (check(TokenType::PLUS) || check(TokenType::MINUS)) {
   337→        TokenType op_type = advance().type;
   338→        auto right = parseMultiplicative();
   339→        left = std::make_shared<BinaryOpNode>(tokenTypeToBinaryOp(op_type), left, right);
   340→    }
   341→
   342→    return left;
   343→}
   344→
   345→std::shared_ptr<ASTNode> Parser::parseMultiplicative() {
   346→    auto left = parseUnary();
   347→
   348→    while (check(TokenType::STAR) || check(TokenType::SLASH) ||
   349→           check(TokenType::PERCENT)) {
   350→        TokenType op_type = advance().type;
   351→        auto right = parseUnary();
   352→        left = std::make_shared<BinaryOpNode>(tokenTypeToBinaryOp(op_type), left, right);
   353→    }
   354→
   355→    return left;
   356→}
   357→
   358→std::shared_ptr<ASTNode> Parser::parseUnary() {
   359→    if (check(TokenType::NOT) || check(TokenType::MINUS) ||
   360→        check(TokenType::AMPERSAND)) {
   361→        TokenType op_type = advance().type;
   362→        auto operand = parseUnary();
   363→        return std::make_shared<UnaryOpNode>(tokenTypeToUnaryOp(op_type), operand);
   364→    }
   365→
   366→    return parsePostfix();
   367→}
   368→
   369→std::shared_ptr<ASTNode> Parser::parsePostfix() {
   370→    auto expr = parsePrimary();
   371→
   372→    while (true) {
   373→        if (match(TokenType::LBRACKET)) {
   374→            // 배열 인덱싱 (현재는 미지원)
   375→            auto index = parseExpression();
   376→            consume(TokenType::RBRACKET, "Expected ']'");
   377→            reportError("Array indexing not yet supported");
   378→            return expr;
   379→        } else if (match(TokenType::LPAREN)) {
   380→            // 함수 호출
   381→            auto args = parseArguments();
   382→            consume(TokenType::RPAREN, "Expected ')'");
   383→
   384→            if (auto ident = std::dynamic_pointer_cast<IdentifierNode>(expr)) {
   385→                expr = std::make_shared<CallNode>(ident->name, args);
   386→            } else {
   387→                reportError("Can only call identifiers");
   388→            }
   389→        } else {
   390→            break;
   391→        }
   392→    }
   393→
   394→    return expr;
   395→}
   396→
   397→std::shared_ptr<ASTNode> Parser::parsePrimary() {
   398→    // 리터럴
   399→    if (check(TokenType::INTEGER)) {
   400→        Token token = advance();
   401→        auto lit = std::make_shared<IntLiteralNode>(std::stoll(token.lexeme));
   402→        return lit;
   403→    }
   404→
   405→    if (check(TokenType::FLOAT)) {
   406→        Token token = advance();
   407→        auto lit = std::make_shared<FloatLiteralNode>(std::stod(token.lexeme));
   408→        return lit;
   409→    }
   410→
   411→    if (check(TokenType::STRING)) {
   412→        Token token = advance();
   413→        auto lit = std::make_shared<StringLiteralNode>(token.lexeme);
   414→        return lit;
   415→    }
   416→
   417→    if (match(TokenType::KW_TRUE)) {
   418→        auto lit = std::make_shared<BoolLiteralNode>(true);
   419→        return lit;
   420→    }
   421→
   422→    if (match(TokenType::KW_FALSE)) {
   423→        auto lit = std::make_shared<BoolLiteralNode>(false);
   424→        return lit;
   425→    }
   426→
   427→    // 식별자
   428→    if (check(TokenType::IDENTIFIER)) {
   429→        Token token = advance();
   430→        return std::make_shared<IdentifierNode>(token.lexeme);
   431→    }
   432→
   433→    // 괄호 식
   434→    if (match(TokenType::LPAREN)) {
   435→        auto expr = parseExpression();
   436→        consume(TokenType::RPAREN, "Expected ')'");
   437→        return expr;
   438→    }
   439→
   440→    reportError("Unexpected token: " + peek().lexeme);
   441→    return nullptr;
   442→}
   443→
   444→std::vector<std::shared_ptr<ASTNode>> Parser::parseArguments() {
   445→    std::vector<std::shared_ptr<ASTNode>> args;
   446→
   447→    if (check(TokenType::RPAREN)) {
   448→        return args;
   449→    }
   450→
   451→    do {
   452→        args.push_back(parseExpression());
   453→    } while (match(TokenType::COMMA));
   454→
   455→    return args;
   456→}
