   462→Token Parser::peek() const {
   463→    if (current < tokens.size()) {
   464→        return tokens[current];
   465→    }
   466→    return tokens.back();  // EOF
   467→}
   468→
   469→Token Parser::peekNext() const {
   470→    if (current + 1 < tokens.size()) {
   471→        return tokens[current + 1];
   472→    }
   473→    return tokens.back();  // EOF
