   476→bool Parser::check(TokenType type) const {
   477→    return peek().type == type;
   478→}
   479→
   480→bool Parser::checkAny(const std::vector<TokenType>& types) const {
   481→    for (const auto& t : types) {
   482→        if (check(t)) return true;
   483→    }
   484→    return false;
   485→}
