   487→Token Parser::advance() {
   488→    Token token = peek();
   489→    if (!isAtEnd()) {
   490→        current++;
   491→    }
   492→    return token;
   493→}
   494→
   495→bool Parser::match(TokenType type) {
   496→    if (check(type)) {
   497→        advance();
   498→        return true;
   499→    }
   500→    return false;
   501→}
   502→
   503→Token Parser::consume(TokenType type, const std::string& message) {
   504→    if (check(type)) {
   505→        return advance();
   506→    }
   507→    reportError(message + " at line " + std::to_string(peek().line));
   508→    return Token();
   509→}
   510→
   511→bool Parser::isAtEnd() const {
   512→    return check(TokenType::END_OF_FILE);
   513→}
   514→
   515→void Parser::reportError(const std::string& message) {
   516→    errors.push_back("[Line " + std::to_string(peek().line) + "] " + message);
   517→}
   518→
   519→void Parser::synchronize() {
   520→    advance();
   521→
   522→    while (!isAtEnd()) {
   523→        if (check(TokenType::KW_FN) || check(TokenType::KW_LET) ||
   524→            check(TokenType::KW_RETURN) || check(TokenType::KW_IF) ||
   525→            check(TokenType::KW_WHILE)) {
   526→            return;
   527→        }
   528→        advance();
   529→    }
   530→}
