   532→BinaryOp Parser::tokenTypeToBinaryOp(TokenType type) {
   533→    switch (type) {
   534→        case TokenType::PLUS:  return BinaryOp::Add;
   535→        case TokenType::MINUS: return BinaryOp::Sub;
   536→        case TokenType::STAR:  return BinaryOp::Mul;
   537→        case TokenType::SLASH: return BinaryOp::Div;
   538→        case TokenType::PERCENT: return BinaryOp::Mod;
   539→        case TokenType::EQ:    return BinaryOp::Equal;
   540→        case TokenType::NE:    return BinaryOp::NotEq;
   541→        case TokenType::LT:    return BinaryOp::Less;
   542→        case TokenType::GT:    return BinaryOp::Greater;
   543→        case TokenType::LE:    return BinaryOp::LessEq;
   544→        case TokenType::GE:    return BinaryOp::GreaterEq;
   545→        case TokenType::AND:   return BinaryOp::And;
   546→        case TokenType::OR:    return BinaryOp::Or;
   547→        case TokenType::ASSIGN: return BinaryOp::Assign;
   548→        default:               return BinaryOp::Add;  // 기본값
   549→    }
   550→}
   551→
   552→UnaryOp Parser::tokenTypeToUnaryOp(TokenType type) {
   553→    switch (type) {
   554→        case TokenType::NOT:       return UnaryOp::Not;
   555→        case TokenType::MINUS:     return UnaryOp::Neg;  // Use Neg instead
   556→        case TokenType::AMPERSAND: return UnaryOp::Address;
   557→        default:                   return UnaryOp::Not;  // 기본값
   558→    }
   559→}
   560→
   561→BuiltinType Parser::tokenTypeToBuiltinType(TokenType type) {
   562→    switch (type) {
   563→        case TokenType::KW_I32:    return BuiltinType::I32;
   564→        case TokenType::KW_I64:    return BuiltinType::I64;
   565→        case TokenType::KW_F32:    return BuiltinType::F32;
   566→        case TokenType::KW_F64:    return BuiltinType::F64;
   567→        case TokenType::KW_BOOL:   return BuiltinType::Bool;
   568→        case TokenType::KW_VOID:   return BuiltinType::Void;
   569→        case TokenType::KW_STRING: return BuiltinType::String;
   570→        default:                   return BuiltinType::Unknown;
   571→    }
   572→}
