   574→// ============================================================================
   575→// 【 Step 3: try-catch-finally 파싱 】
   576→// ============================================================================
   577→
   578→std::shared_ptr<TryCatchNode> Parser::parseTryCatch() {
   579→    if (!match(TokenType::KW_TRY)) {
   580→        reportError("Expected 'try'");
   581→        return nullptr;
   582→    }
   583→
   584→    // try 블록 파싱
   585→    auto try_block = parseBlock();
   586→    if (!try_block) {
   587→        reportError("parseTryCatch: Failed to parse try block");
   588→        return nullptr;
   589→    }
   590→
   591→    // catch 블록들 파싱
   592→    std::vector<CatchClause> catch_clauses;
   593→    while (check(TokenType::KW_CATCH)) {
   594→        if (!match(TokenType::KW_CATCH)) break;
   595→
   596→        // catch (e: ExceptionType) 파싱
   597→        if (!match(TokenType::LPAREN)) {
   598→            reportError("Expected '(' in catch clause");
   599→            break;
   600→        }
   601→
   602→        Token var_token = consume(TokenType::IDENTIFIER, "Expected exception variable");
   603→        consume(TokenType::COLON, "Expected ':' after variable");
   604→        Token type_token = consume(TokenType::IDENTIFIER, "Expected exception type");
   605→
   606→        if (!match(TokenType::RPAREN)) {
   607→            reportError("Expected ')' in catch clause");
   608→            break;
   609→        }
   610→
   611→        // catch 블록 파싱
   612→        auto catch_block = parseBlock();
   613→        if (!catch_block) {
   614→            reportError("parseTryCatch: Failed to parse catch block");
   615→            break;
   616→        }
   617→
   618→        catch_clauses.push_back({
   619→            var_token.lexeme,
   620→            type_token.lexeme,
   621→            catch_block
   622→        });
   623→    }
   624→
   625→    // finally 블록 파싱 (선택사항)
   626→    std::shared_ptr<BlockNode> finally_block = nullptr;
   627→    if (check(TokenType::KW_FINALLY)) {
   628→        if (!match(TokenType::KW_FINALLY)) {
   629→            reportError("Expected 'finally'");
   630→        }
   631→        finally_block = parseBlock();
   632→        if (!finally_block) {
   633→            reportError("parseTryCatch: Failed to parse finally block");
   634→        }
   635→    }
   636→
   637→    return std::make_shared<TryCatchNode>(try_block, catch_clauses, finally_block);
   638→}
