fn digit_count(n: i64) -> i64 {
    if n == 0 {
        return 1;
    }

    let count: i64 = 0;
    let temp: i64 = n;

    while temp > 0 {
        count = count + 1;
        temp = temp / 10;
    }

    return count;
}

// Sum digits of a number
fn sum_digits(n: i64) -> i64 {
    let sum: i64 = 0;
    let temp: i64 = n;

    while temp > 0 {
        sum = sum + (temp % 10);
        temp = temp / 10;
    }

    return sum;
}

// Reverse a number
fn reverse_number(n: i64) -> i64 {
    let result: i64 = 0;
    let temp: i64 = n;

    while temp > 0 {
        result = result * 10 + (temp % 10);
        temp = temp / 10;
    }

    return result;
}

