fn array_sum(a: i64, b: i64, c: i64) -> i64 {
    return a + b + c;
}

// Find maximum in array
fn array_max(a: i64, b: i64, c: i64) -> i64 {
    let max_val: i64 = a;

    if b > max_val {
        max_val = b;
    }

    if c > max_val {
        max_val = c;
    }

    return max_val;
}

// Find minimum in array
fn array_min(a: i64, b: i64, c: i64) -> i64 {
    let min_val: i64 = a;

    if b < min_val {
        min_val = b;
    }

    if c < min_val {
        min_val = c;
    }

    return min_val;
}

// Count occurrences of value in array
fn array_count(target: i64, a: i64, b: i64, c: i64) -> i64 {
    let count: i64 = 0;

    if a == target {
        count = count + 1;
    }

    if b == target {
        count = count + 1;
    }

    if c == target {
        count = count + 1;
    }

    return count;
}

// Average of array elements
fn array_avg(a: i64, b: i64, c: i64) -> i64 {
    return (a + b + c) / 3;
