    if a == target {
        return true;
    }

    if b == target {
        return true;
    }

    if c == target {
        return true;
    }

    return false;
}

// Swap two elements (returns larger first)
fn array_swap(a: i64, b: i64) -> i64 {
    if a > b {
        return a;
    }
    return b;
}

// Filter: return only even numbers from array
fn array_filter_even(a: i64, b: i64, c: i64) -> i64 {
    let count: i64 = 0;

    if (a % 2) == 0 {
        count = count + 1;
    }

    if (b % 2) == 0 {
        count = count + 1;
    }

    if (c % 2) == 0 {
        count = count + 1;
    }

    return count;
