## 5. 실제 코드 예제 모음

### 피보나치 (fibonacci.z)
```z
fn fibonacci(n: i64) -> i64 {
    if n <= 1 {
        return n;
    }
    let a: i64 = 0;
    let b: i64 = 1;
    let i: i64 = 2;
    while i <= n {
        let temp: i64 = a + b;
        a = b;
        b = temp;
        i = i + 1;
    }
    return b;
}

fn main() -> i64 {
    return fibonacci(10);
}
```

### 최대값 (condition.z)
```z
fn max(a: i64, b: i64) -> i64 {
    if a > b {
        return a;
    } else {
        return b;
    }
}
```

### 루프 합산 (test_loop.z)
```z
fn main() -> i64 {
    let sum: i64 = 0;
    let i: i64 = 1;
    while i <= 5 {
        sum = sum + i;
        i = i + 1;
    }
    return sum;
}
```

### 재귀 팩토리얼 (stdlib/math.z)
```z
fn factorial(n: i64) -> i64 {
    if n <= 1 {
        return 1;
    }
    return n * factorial(n - 1);
}
```

### GCD (stdlib/math.z)
```z
fn gcd(a: i64, b: i64) -> i64 {
    let x: i64 = a;
    let y: i64 = b;
    while y != 0 {
        let temp: i64 = y;
        y = x % y;
        x = temp;
    }
    return x;
}
```

### 예외 처리 (test_try_catch.z)
```z
fn safe_divide(a: i64, b: i64) -> i64 {
    try {
        if b == 0 {
            return -1;
        }
        return a / b;
    } catch (e: DivisionError) {
        return -1;
    } finally {
        return 0;
    }
}
```

